INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('วิดพื้น', 'Push-up', 'เริ่มต้น', 'หน้าอก', 'หัวไหล่, หลังแขน, แกนกลางลำตัว', 'น้ำหนักตัว', '5-10 นาที', 'ท่าพื้นฐานที่ช่วยสร้างกล้ามเนื้อหน้าอก หัวไหล่ และหลังแขน โดยใช้เพียงน้ำหนักตัว', 'วางมือบนพื้นให้กว้างกว่าช่วงไหล่เล็กน้อย | เหยียดขาตรง เกร็งหน้าท้องและก้นเพื่อให้ลำตัวเป็นเส้นตรงขนานกับพื้น | หายใจเข้า ค่อยๆ งอศอกลดลำตัวลงจนหน้าอกเกือบแตะพื้น (ศอกกางออกประมาณ 45 องศา) | หายใจออก ออกแรงดันจากหน้าอกเพื่อดันตัวกลับขึ้นมา', NULL, 'https://www.youtube.com/embed/IODxDxX7oi4'),
('ดันอกด้วยดัมเบล', 'Dumbbell Bench Press', 'เริ่มต้น', 'หน้าอก', 'ไหล่, หลังแขน', 'ดัมเบล', '10-15 นาที', 'ท่าสร้างกล้ามเนื้ออกที่ช่วยให้กล้ามเนื้อซ้ายขวาออกแรงเท่ากัน', 'นอนหงายบนม้านั่ง ถือดัมเบลระดับอก | หายใจออกพร้อมออกแรงดันดัมเบลขึ้นจนสุดแขน | หายใจเข้า ค่อยๆ ลดดัมเบลลงกลับสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/VmB1G1K7v94'),
('ดันอกบนด้วยดัมเบล', 'Incline Dumbbell Press', 'ปานกลาง', 'หน้าอก', 'ไหล่, หลังแขน', 'ดัมเบล', '10-15 นาที', 'ท่าเน้นสร้างกล้ามเนื้ออกส่วนบนให้เต็มและสวยงาม', 'ปรับเบาะเอียง 30-45 องศา นั่งพิงแล้วถือดัมเบลระดับอก | ดันดัมเบลขึ้นด้านบนจนแขนตึง | ค่อยๆ ลดดัมเบลลงช้าๆ กลับสู่ระดับอก', NULL, 'https://www.youtube.com/embed/8iPEnn-ltC8'),
('อินคไลน์ดัมเบลฟลาย', 'Incline Dumbbell Fly', 'ปานกลาง', 'หน้าอก', 'ไหล่ด้านหน้า', 'ดัมเบล', '10-15 นาที', 'ท่าที่เน้นการยืดและบีบกล้ามเนื้ออก สร้างความกว้างของหน้าอกส่วนบน', 'นอนหงายบนเบาะเอียง ถือดัมเบลเหยียดแขนตึงเหนืออก | กางแขนออกด้านข้างโดยงอศอกเล็กน้อย จนรู้สึกตึงที่หน้าอก | หุบแขนกลับมาเกร็งหน้าอกบนเหมือนกำลังกอดต้นไม้ใหญ่', NULL, 'https://www.youtube.com/embed/bDaB-MMzeF8'),
('เพ็คเด็กซ์ ฟลาย', 'Pec Deck Fly', 'เริ่มต้น', 'หน้าอก', 'ไหล่ด้านหน้า', 'เครื่องเล่น', '10-15 นาที', 'เครื่องเล่นที่ช่วยโฟกัสหน้าอกได้ง่าย เหมาะสำหรับมือใหม่', 'นั่งหลังตรงแนบเบาะ จับด้ามจับของเครื่องให้ศอกอยู่ระดับอก | หายใจออก ออกแรงหนีบแขนเข้าหากันที่หน้าอก | หายใจเข้า ค่อยๆ ผ่อนแขนออกกลับสู่ท่าเริ่มต้นช้าๆ', NULL, 'https://www.youtube.com/embed/eGjt4jcEA_U'),
('เครื่องดันอก', 'Chest Press Machine', 'เริ่มต้น', 'หน้าอก', 'ไหล่, หลังแขน', 'เครื่องเล่น', '10-15 นาที', 'ปลอดภัยและควบคุมทิศทางได้ง่ายกว่าการใช้ฟรีเวท', 'นั่งบนเครื่อง ปรับเบาะให้มือจับอยู่ระดับกลางอก | หายใจออก ออกแรงดันมือจับออกไปจนสุดข้อศอก | หายใจเข้า ผ่อนแรงกลับมาอย่างควบคุม', NULL, 'https://www.youtube.com/embed/xUm0BiZCWlQ'),
('วิดพื้นแบบมือสูง', 'Incline Push-up', 'เริ่มต้น', 'หน้าอก', 'ไหล่, หลังแขน', 'น้ำหนักตัว', '5-10 นาที', 'วิดพื้นแบบวางมือบนพื้นยกระดับ ช่วยให้ทำได้ง่ายขึ้นสำหรับมือใหม่ โฟกัสอกล่าง', 'วางมือบนเก้าอี้หรือขอบเตียง ลำตัวตรงเป็นแผ่นกระดาน | ย่อตัวลงจนอกเกือบแตะเก้าอี้ | ออกแรงดันตัวกลับขึ้นมาจนสุดแขน', NULL, 'https://www.youtube.com/embed/Me9bHFAxnCs'),
('วิดพื้นแบบเท้าสูง', 'Decline Push-up', 'ขั้นสูง', 'หน้าอก', 'ไหล่, หลังแขน', 'น้ำหนักตัว', '5-10 นาที', 'วิดพื้นแบบยกเท้าสูง เพิ่มความท้าทายและเน้นอกบน', 'วางเท้าบนเก้าอี้ วางมือบนพื้นกว้างกว่าไหล่ | ย่อตัวลงจนหน้าอกใกล้พื้น | ออกแรงดันตัวกลับขึ้นสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/SKPab2YC8BE'),
('เคเบิลครอสโอเวอร์', 'Cable Crossover', 'ปานกลาง', 'หน้าอก', 'แกนกลางลำตัว', 'เครื่องเล่น', '10-15 นาที', 'ใช้สายเคเบิลเพื่อสร้างแรงต้านตลอดการเคลื่อนไหว', 'ยืนตรงกลางเครื่องเคเบิล จับสายเคเบิลระดับสูง | โน้มตัวเล็กน้อย ดึงสายเคเบิลมาไขว้กันที่หน้าอกล่าง บีบกล้ามเนื้ออก | ค่อยๆ ปล่อยแขนกลับไปจุดเริ่มต้นโดยรักษาการงอศอกไว้เล็กน้อย', NULL, 'https://www.youtube.com/embed/taI4XduLpTk');
INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('ดึงข้อ', 'Pull-up', 'ขั้นสูง', 'หลัง', 'หน้าแขน, หลังส่วนบน', 'น้ำหนักตัว', '5-10 นาที', 'ท่าสร้างความกว้างของแผ่นหลังที่ดีที่สุดโดยใช้น้ำหนักตัว', 'โหนบาร์โดยจับกว้างกว่าไหล่ ฝ่ามือหันออกจากตัว | หายใจออก ดึงตัวขึ้นจนคางเลยบาร์และบีบสะบัก | หายใจเข้า ค่อยๆ ลดตัวลงจนแขนเหยียดตึง', NULL, 'https://www.youtube.com/embed/eGo4IYILThM'),
('ดัมเบลโรว์แขนเดียว', 'One-Arm Dumbbell Row', 'ปานกลาง', 'หลัง', 'หลังส่วนบน, หน้าแขน', 'ดัมเบล', '10-15 นาที', 'ท่าสร้างแผ่นหลังให้หนาและแข็งแรง ช่วยปรับสมดุลกล้ามเนื้อซ้าย-ขวา', 'วางมือและเข่าข้างหนึ่งบนม้ากระดาน ลำตัวขนานกับพื้น | มืออีกข้างถือดัมเบล ปล่อยแขนตึงลงด้านล่าง | ดึงดัมเบลขึ้นมาด้านข้างลำตัวโดยบีบสะบักเข้าหากัน | ค่อยๆ ลดดัมเบลลงกลับสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/d2zXIXE1rU0'),
('แลทพูลดาวน์', 'Lat Pulldown', 'เริ่มต้น', 'หลัง', 'หน้าแขน, ไหล่ด้านหลัง', 'เครื่องเล่น', '10-15 นาที', 'ท่าฝึกกล้ามเนื้อหลังที่ปลอดภัยและควบคุมง่าย เหมาะสำหรับผู้ที่ยังดึงข้อไม่ไหว', 'นั่งบนเครื่อง ล็อกต้นขาให้แน่น จับบาร์กว้างกว่าหัวไหล่ | เอนหลังเล็กน้อย ดึงบาร์ลงมาที่อกส่วนบน | บีบกล้ามเนื้อหลังค้างไว้ 1 วินาที | ค่อยๆ ปล่อยบาร์ขึ้นจนแขนเหยียดตึง', NULL, 'https://www.youtube.com/embed/CAwf7n6Luuc'),
('ท่านั่งดึงเคเบิล', 'Seated Cable Row', 'เริ่มต้น', 'หลัง', 'หน้าแขน', 'เครื่องเล่น', '10-15 นาที', 'สร้างความหนาให้แผ่นหลัง ควบคุมโฟกัสได้ง่าย', 'นั่งบนเครื่อง เท้ายันแท่น จับที่จับด้วยสองมือ | ดึงที่จับเข้าหาหน้าท้อง ยืดอกและบีบสะบักหลัง | ปล่อยแขนกลับจนแผ่นหลังถูกยืดออก', NULL, 'https://www.youtube.com/embed/GZbfZ033f74'),
('ก้มตัวดึงดัมเบล', 'Bent-Over Row', 'ปานกลาง', 'หลัง', 'หน้าแขน', 'ดัมเบล', '10-15 นาที', 'ท่าก้มตัวดึงดัมเบล สร้างความแข็งแรงให้แผ่นหลังโดยรวม', 'ถือดัมเบล 2 ข้าง ย่อเข่าและโน้มตัวไปด้านหน้าให้หลังตรงเกือบขนานพื้น | ดึงดัมเบลขึ้นมาข้างเอว บีบสะบักหลัง | ลดดัมเบลลงกลับสู่ท่าเริ่มต้นช้าๆ', NULL, 'https://www.youtube.com/embed/6TSZeH-N1nQ'),
('ดึงข้อแบบหงายมือ', 'Chin-up', 'ปานกลาง', 'หลัง', 'หน้าแขน', 'น้ำหนักตัว', '5-10 นาที', 'คล้ายดึงข้อแต่หงายมือเข้าหาตัว จะได้หน้าแขนช่วยออกแรงมากขึ้น', 'โหนบาร์ หงายฝ่ามือเข้าหาตัว จับกว้างระดับหัวไหล่ | ดึงตัวขึ้นจนคางเลยบาร์ | ลดตัวลงช้าๆ จนสุดแขน', NULL, 'https://www.youtube.com/embed/brhRXlOhsAM'),
('หลังล่างด้วยเครื่อง', 'Back Extension', 'เริ่มต้น', 'หลัง', 'ก้น, หลังต้นขา', 'เครื่องเล่น', '10-15 นาที', 'เสริมความแข็งแรงให้หลังส่วนล่าง ป้องกันอาการปวดหลัง', 'ล็อกข้อเท้าบนเครื่อง พาดหน้าขาบนเบาะ | ก้มตัวลงจนรู้สึกตึงที่หลังต้นขา | เกร็งหลังล่างยกตัวขึ้นมาจนลำตัวเป็นเส้นตรง (ระวังอย่าแอ่นหลังมากเกินไป)', NULL, 'https://www.youtube.com/embed/ph3pddpKzzw'),
('ดึงเคเบิลเหยียดแขนตรง', 'Straight Arm Pulldown', 'ปานกลาง', 'หลัง', 'แกนกลางลำตัว', 'เครื่องเล่น', '10-15 นาที', 'ท่าแยกส่วน (Isolation) ที่เน้นปีกหลังโดยไม่ใช้หน้าแขนช่วย', 'จับบาร์กว้างระดับไหล่ ยืนห่างเครื่องเล็กน้อย โน้มตัวไปข้างหน้า | ล็อกแขนให้ตึง กดบาร์ลงมาจนแตะหน้าขา บีบปีกหลัง | ค่อยๆ ปล่อยบาร์ขึ้นกลับไปที่ระดับสายตา', NULL, 'https://www.youtube.com/embed/Gj20s2qTofA'),
('ดึงหลังด้วยบาร์วี', 'V-Bar Lat Pulldown', 'เริ่มต้น', 'หลัง', 'หน้าแขน, ทราป', 'เครื่องเล่น', '10-15 นาที', 'เน้นความหนาของแผ่นหลังช่วงกลางและกล้ามเนื้อระหว่างสะบัก', 'นั่งบนเครื่อง สอดเข่าใต้เบาะ จับบาร์รูปตัววี | ยืดอก ดึงบาร์วีลงมาแตะที่อกส่วนบน บีบสะบักเข้าหากัน | ปล่อยบาร์ขึ้นจนแผ่นหลังถูกยืดออกสุด', NULL, 'https://www.youtube.com/embed/KjGveHk-Tls');
INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('สควอทน้ำหนักตัว', 'Bodyweight Squat', 'เริ่มต้น', 'ขา', 'ก้น, แกนกลางลำตัว', 'น้ำหนักตัว', '5-10 นาที', 'ท่าพื้นฐานที่สุดของมนุษย์ สร้างกำลังหน้าขาและสะโพก', 'ยืนกางขากว้างระดับหัวไหล่ เปิดปลายเท้าออกเล็กน้อย | ยืดอก หลังตรง เกร็งหน้าท้อง พร้อมหายใจเข้า | ดันสะโพกไปด้านหลัง ย่อตัวลงจนต้นขาขนานกับพื้น | ออกแรงดันจากส้นเท้าเพื่อยืนขึ้น พร้อมหายใจออก', NULL, 'https://www.youtube.com/embed/xqvCmoLULNY'),
('ก็อบเล็ตสควอท (อุ้มดัมเบล)', 'Dumbbell Goblet Squat', 'เริ่มต้น', 'ขา', 'ก้น, แกนกลางลำตัว', 'ดัมเบล', '10-15 นาที', 'ท่าสร้างความแข็งแรงให้ช่วงล่างและแกนกลางลำตัว ช่วยฝึกฟอร์มการสควอทที่ถูกต้อง', 'ยืนแยกเท้ากว้างระดับไหล่ ถือดัมเบลแนวตั้ง 1 ลูกไว้แนบอก | ดันสะโพกไปด้านหลังและงอเข่า ย่อตัวลงเหมือนกำลังจะนั่งเก้าอี้ | ย่อลงจนต้นขาขนานกับพื้นหรือต่ำกว่า | ออกแรงดันจากส้นเท้าเพื่อยืนขึ้นกลับสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/MeIiIdhcXT4'),
('ลันจ์', 'Lunges', 'เริ่มต้น', 'ขา', 'ก้น, แกนกลางลำตัว', 'น้ำหนักตัว', '10-15 นาที', 'ช่วยเพิ่มความแข็งแรงของขาและการทรงตัว', 'ยืนตรง เอามือเท้าเอว | ก้าวขาข้างหนึ่งไปข้างหน้ายาวๆ | ย่อตัวลงตั้งฉากจนเข่าหลังเกือบแตะพื้น | ออกแรงดันจากส้นเท้าหน้า เพื่อกลับมายืนท่าเดิม แล้วสลับข้าง', NULL, 'https://www.youtube.com/embed/QOVaHwm-Q6U'),
('เครื่องดันขา', 'Leg Press', 'เริ่มต้น', 'ขา', 'ก้น, หลังต้นขา', 'เครื่องเล่น', '10-15 นาที', 'ยกน้ำหนักได้เยอะโดยไม่ต้องพะวงเรื่องการทรงตัวของแผ่นหลัง', 'นั่งแนบเบาะบนเครื่อง วางเท้าบนแป้นกว้างระดับไหล่ | ปลดล็อกเครื่อง หายใจเข้าแล้วงอเข่าลดแป้นลงมาจนเข่าตั้งฉาก | หายใจออก ออกแรงถีบแป้นกลับไปจนสุด (อย่าล็อกข้อเข่าตึง)', NULL, 'https://www.youtube.com/embed/IZxyjW7OSvc'),
('ก้าวเหยียดขาด้วยดัมเบล', 'Dumbbell Lunge', 'ปานกลาง', 'ขา', 'ก้น, แกนกลางลำตัว', 'ดัมเบล', '10-15 นาที', 'ฝึกการทรงตัวและสร้างกล้ามเนื้อขาทีละข้างแบบมีแรงต้าน', 'ยืนถือดัมเบลสองข้างแนบลำตัว | ก้าวเท้าหนึ่งไปด้านหน้า ย่อตัวลงจนเข่าหลังเกือบแตะพื้น | ดันตัวกลับมายืนที่เดิม แล้วสลับข้าง', NULL, 'https://www.youtube.com/embed/D7KaRcUTQeE'),
('เครื่องเตะหน้าขา', 'Leg Extension', 'เริ่มต้น', 'ขา', 'ไม่มี', 'เครื่องเล่น', '10-15 นาที', 'ท่าแยกส่วนที่เน้นกล้ามเนื้อหน้าขา (Quads) โดยตรง สร้างความคมชัด', 'นั่งพิงเบาะให้เข่าพอดีกับข้อพับเครื่อง สอดข้อเท้าไว้ใต้เบาะรอง | หายใจออก เตะขาขึ้นมาจนเข่าตึง เกร็งหน้าขาค้างไว้ 1 วินาที | หายใจเข้า ค่อยๆ ลดขาลงต้านน้ำหนัก', NULL, 'https://www.youtube.com/embed/YyvSfVjQeL0'),
('เครื่องพับหลังขา', 'Leg Curl', 'เริ่มต้น', 'ขา', 'น่อง', 'เครื่องเล่น', '10-15 นาที', 'เน้นสร้างกล้ามเนื้อหลังต้นขา (Hamstrings) ป้องกันอาการบาดเจ็บที่เข่า', 'นอนคว่ำ (หรือนั่ง) บนเครื่อง สอดข้อเท้าไว้ใต้เบาะล็อค | พับขาเข้าหาตัว เกร็งหลังต้นขาให้สุด | ปล่อยขาออกช้าๆ อย่างควบคุมจังหวะ', NULL, 'https://www.youtube.com/embed/F488k67BTNo'),
('เขย่งน่อง', 'Standing Calf Raise', 'เริ่มต้น', 'ขา', 'ไม่มี', 'น้ำหนักตัว', '5-10 นาที', 'สร้างกล้ามเนื้อน่อง สามารถทำได้บนพื้นราบหรือยืนขอบบันไดเพื่อยืดกล้ามเนื้อให้สุด', 'ยืนตรงบนพื้นหรือขอบสเต็ป (หาที่จับทรงตัว) | เขย่งส้นเท้าขึ้นให้สูงที่สุด เกร็งน่องค้างไว้ | ลดส้นเท้าลงจนรู้สึกตึงที่น่อง', NULL, 'https://www.youtube.com/embed/-M4-G8p8fmc'),
('ดัมเบล อาร์ดีแอล', 'Dumbbell RDL', 'ปานกลาง', 'ขา', 'ก้น, หลังส่วนล่าง', 'ดัมเบล', '10-15 นาที', 'เน้นการพับสะโพก (Hinge) ยืดกล้ามเนื้อหลังต้นขาได้ดีเยี่ยม', 'ถือดัมเบลไว้หน้าต้นขา ยืนกางขากว้างระดับสะโพก | ยืดอก ดันสะโพกไปด้านหลัง ก้มตัวลงโดยที่แผ่นหลังตรง เข่างอเพียงเล็กน้อย | เมื่อดัมเบลลงถึงใต้เข่า ให้ดันสะโพกกลับมายืนตรงและบีบก้น', NULL, 'https://www.youtube.com/embed/JCXUYuzwNrM'),
('สควอทขาเดียว', 'Bulgarian Split Squat', 'ขั้นสูง', 'ขา', 'ก้น, แกนกลางลำตัว', 'น้ำหนักตัว', '10-15 นาที', 'ท่าฝึกขาที่โหดและได้ผลดีมาก เน้นขาทีละข้าง ต้องใช้การทรงตัวสูง', 'ยืนหันหลังให้ม้านั่ง พาดหลังเท้าข้างหนึ่งไว้บนม้านั่ง | ย่อตัวลงจนต้นขาด้านหน้าขนานกับพื้น (เข่าหน้าไม่เลยปลายเท้ามากเกินไป) | ออกแรงถีบจากส้นเท้าหน้า ดันตัวขึ้นกลับสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/2C-uNgKwPLE'),
('ดันสะโพกด้วยดัมเบล', 'Dumbbell Hip Thrust', 'ปานกลาง', 'ขา', 'หลังต้นขา', 'ดัมเบล', '10-15 นาที', 'ท่าปั้นก้นที่ดีเยี่ยม โดยใช้ดัมเบลวางที่หน้าขาเพื่อเพิ่มแรงต้าน', 'นั่งบนพื้น พิงแผ่นหลังช่วงสะบักไว้บนม้านั่ง วางดัมเบลไว้ที่รอยพับสะโพก | ออกแรงจากส้นเท้า ดันสะโพกขึ้นจนลำตัวขนานพื้นและบีบก้นแน่นๆ | ค่อยๆ ลดสะโพกลงเกือบแตะพื้น แล้วดันขึ้นใหม่', NULL, 'https://www.youtube.com/embed/xDQkEvq92nI');
INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('ดันไหล่ด้วยดัมเบล', 'Dumbbell Shoulder Press', 'ปานกลาง', 'หัวไหล่', 'หลังแขน, อกส่วนบน', 'ดัมเบล', '10-15 นาที', 'ท่าหลักในการสร้างกล้ามเนื้อหัวไหล่ให้กลมสวยและเพิ่มความแข็งแรงในการดัน', 'นั่งพิงเบาะให้หลังตรง ถือดัมเบลยกขึ้นมาไว้ที่ระดับหู | หันฝ่ามือไปด้านหน้า กางศอกออกให้ตั้งฉากกับพื้น | หายใจออก พร้อมออกแรงดันดัมเบลขึ้นเหนือศีรษะจนแขนเกือบตึง | หายใจเข้า ค่อยๆ ลดดัมเบลลงกลับมาระดับหู', NULL, 'https://www.youtube.com/embed/qEwKCR5JCog'),
('กางแขนด้วยดัมเบล', 'Dumbbell Lateral Raise', 'เริ่มต้น', 'หัวไหล่', 'ทราป', 'ดัมเบล', '10-15 นาที', 'ท่าหลักในการสร้างไหล่ด้านข้างให้ดูกว้างเป็นรูปตัว V', 'ยืนถือดัมเบลข้างลำตัว งอศอกเล็กน้อย | ยกแขนกางออกด้านข้างจนดัมเบลสูงระดับหัวไหล่ (เทน้ำจากเหยือกเล็กน้อย) | ลดแขนลงช้าๆ เพื่อต้านแรงโน้มถ่วง', NULL, 'https://www.youtube.com/embed/3VcKaXpzqRo'),
('ยกแขนหน้าด้วยดัมเบล', 'Dumbbell Front Raise', 'เริ่มต้น', 'หัวไหล่', 'อกส่วนบน', 'ดัมเบล', '5-10 นาที', 'เน้นสร้างกล้ามเนื้อไหล่ด้านหน้าให้เต็มชัด', 'ยืนถือดัมเบลไว้หน้าต้นขา แขนตึง | ยกแขนขึ้นตรงๆ มาด้านหน้าจนถึงระดับหัวไหล่ | ควบคุมจังหวะลดแขนลงช้าๆ', NULL, 'https://www.youtube.com/embed/-t7fuZ0KhDA'),
('เครื่องดันไหล่', 'Shoulder Press Machine', 'เริ่มต้น', 'หัวไหล่', 'หลังแขน', 'เครื่องเล่น', '10-15 นาที', 'สร้างไหล่แบบปลอดภัยและมั่นคง เครื่องช่วยประคองทิศทางให้', 'นั่งบนเครื่อง หลังแนบเบาะ จับด้ามจับให้พอดีระดับหู | ดันแขนขึ้นด้านบนจนสุด | ลดแขนลงกลับสู่ท่าเริ่มต้นช้าๆ', NULL, 'https://www.youtube.com/embed/WvLMauqrnK8'),
('กางแขนหลังด้วยดัมเบล', 'Dumbbell Reverse Fly', 'ปานกลาง', 'หัวไหล่', 'หลังส่วนบน', 'ดัมเบล', '10-15 นาที', 'ท่าก้มตัวกางแขน ช่วยปั้นไหล่ด้านหลังให้กลมสวยและแก้ไหล่ห่อ', 'พับสะโพกก้มตัวโน้มไปด้านหน้า แผ่นหลังขนานพื้น ถือดัมเบลแขนห้อยลง | กางแขนออกไปด้านข้างและไปด้านหลัง บีบไหล่หลัง | ลดแขนลงกลับสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/9Gf-OuBCtPE'),
('เครื่องกางไหล่หลัง', 'Reverse Pec Deck', 'เริ่มต้น', 'หัวไหล่', 'หลังส่วนบน', 'เครื่องเล่น', '10-15 นาที', 'เครื่องเล่นเดียวกับ Pec Deck แต่นั่งหันหน้าเข้าเครื่อง โฟกัสไหล่หลังได้เน้นๆ', 'นั่งหันหน้าอกเข้าหาเบาะเครื่อง จับด้ามจับเหยียดแขนตึง | ดึงแขนกางออกไปด้านหลังจนสุด บีบไหล่หลังค้างไว้ | ปล่อยแขนกลับมาช้าๆ', NULL, 'https://www.youtube.com/embed/5yKcCWCrNhM'),
('ยักไหล่ด้วยดัมเบล', 'Dumbbell Shrug', 'เริ่มต้น', 'หัวไหล่', 'คอ', 'ดัมเบล', '5-10 นาที', 'ท่าสร้างกล้ามเนื้อบ่า (Traps) ให้หนาและแข็งแรง', 'ยืนถือดัมเบลข้างลำตัว ปล่อยแขนตึงตรง | ออกแรงยักไหล่ขึ้นสูงเหมือนพยายามจะให้ไหล่แตะใบหู | เกร็งค้างไว้ 1 วินาที แล้วลดไหล่ลงสุดเพื่อยืดกล้ามเนื้อ', NULL, 'https://www.youtube.com/embed/g6qbq4LfWQY'),
('ดันไหล่อาร์โนลด์', 'Arnold Press', 'ขั้นสูง', 'หัวไหล่', 'หลังแขน', 'ดัมเบล', '10-15 นาที', 'ท่าคิดค้นโดย Arnold Schwarzenegger เน้นการหมุนข้อมือเพื่อให้โดนไหล่ครบทุกมัด', 'นั่งถือดัมเบลระดับคาง หันฝ่ามือเข้าหาหน้าตัวเอง | ดันดัมเบลขึ้นด้านบน พร้อมหมุนข้อมือหันฝ่ามือออกไปด้านนอก | ตอนลดดัมเบลลง ให้หมุนข้อมือกลับมาในท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/6Z15_WzPEcE'),
('ไพค์พุชอัป (วิดพื้นยกสะโพก)', 'Pike Push-up', 'ขั้นสูง', 'หัวไหล่', 'หน้าอก, หลังแขน', 'น้ำหนักตัว', '5-10 นาที', 'การวิดพื้นแบบยกสะโพกสูง เน้นถ่ายน้ำหนักตัวไปที่หัวไหล่เต็มๆ สร้างไหล่กว้างโดยไม่ใช้อุปกรณ์', 'ตั้งท่าก้มตัวเป็นรูปตัว V คว่ำ (ก้นชี้ขึ้นฟ้า ขาและแขนตึง) | งอศอกย่อศีรษะลงแตะพื้นด้านหน้าระหว่างมือ | ดันตัวกลับขึ้นไปในท่า V คว่ำ', NULL, 'https://www.youtube.com/embed/sposDXWEB0A'),
('เฟสพูล (ดึงเคเบิลหน้าระดับตา)', 'Face Pull', 'ปานกลาง', 'หัวไหล่', 'หลังส่วนบน', 'เครื่องเล่น', '5-10 นาที', 'ท่าปรับบุคลิกภาพยอดฮิต แก้อาการไหล่ห่อ และสร้างไหล่หลังให้กลม', 'ปรับสายเคเบิลไว้ระดับสายตา ใช้หัวจับแบบเชือก (Rope) | ดึงเชือกแยกออกเข้าหาใบหน้า พร้อมกางศอกออกด้านข้าง | บีบสะบักและไหล่หลังค้างไว้ แล้วปล่อยเชือกกลับช้าๆ', NULL, 'https://www.youtube.com/embed/rep-qVOkqgk');
INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('ดัมเบลเคิร์ล (ยกหน้าแขน)', 'Dumbbell Bicep Curl', 'เริ่มต้น', 'แขน', 'ปลายแขน', 'ดัมเบล', '10-15 นาที', 'ท่าคลาสสิกตลอดกาลสำหรับสร้างลูกหนู (หน้าแขน) ให้ปูดชัดเจน', 'ยืนหรือนั่ง ล็อกข้อศอกแนบลำตัว ถือดัมเบลหงายมือ | พับข้อศอกยกดัมเบลขึ้นหาไหล่ โดยไม่ขยับต้นแขน | ค่อยๆ ลดดัมเบลลงจนแขนตึง เพื่อยืดกล้ามเนื้อหน้าแขน', NULL, 'https://www.youtube.com/embed/ykJmrZ5v0Oo'),
('แฮมเมอร์เคิร์ล (ยกดัมเบลแนวตั้ง)', 'Hammer Curl', 'เริ่มต้น', 'แขน', 'ปลายแขน', 'ดัมเบล', '10-15 นาที', 'จับดัมเบลแบบตั้งตรง คล้ายจับค้อน ช่วยสร้างกล้ามเนื้อแขนด้านข้างให้ดูหนาและเต็มขึ้น', 'ถือดัมเบลแนบลำตัว หันฝ่ามือเข้าหาต้นขา | พับศอกยกดัมเบลขึ้นตรงๆ โดยรักษามุมข้อมือไว้ | ลดดัมเบลลงช้าๆ', NULL, 'https://www.youtube.com/embed/zC3nLlEvin4'),
('เครื่องม้วนหน้าแขน', 'Bicep Curl Machine', 'เริ่มต้น', 'แขน', 'ไม่มี', 'เครื่องเล่น', '10-15 นาที', 'เครื่องช่วยล็อกข้อศอกให้นิ่ง ทำให้โฟกัสหน้าแขนได้ 100% โดยไม่ใช้การเหวี่ยงตัวช่วย', 'นั่งบนเครื่อง วางหลังแขนแนบลงบนเบาะรอง จับด้ามจับ | ออกแรงม้วนด้ามจับเข้าหาตัวให้สุด | ปล่อยน้ำหนักกลับช้าๆ จนแขนเกือบตึง', NULL, 'https://www.youtube.com/embed/5FZaB8kE76I'),
('ยืดหลังแขน', 'Dumbbell Tricep Extension', 'ปานกลาง', 'แขน', 'ไม่มี', 'ดัมเบล', '10-15 นาที', 'ท่ายกน้ำหนักยืดเหนือศีรษะ สร้างกล้ามเนื้อหลังแขนให้กระชับ ป้องกันแขนห้อยย้อย', 'นั่งพิงเบาะ ถือดัมเบล 1 ลูกด้วยสองมือ ยกขึ้นเหนือศีรษะจนแขนตึง | งอข้อศอกลดดัมเบลไปด้านหลังศีรษะให้ลึกที่สุด | ออกแรงจากหลังแขน ยืดดัมเบลกลับขึ้นสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/nRiJVZDpdL0'),
('กดหลังแขน', 'Tricep Pushdown', 'เริ่มต้น', 'แขน', 'ไม่มี', 'เครื่องเล่น', '10-15 นาที', 'ใช้สายเคเบิลกดลงด้านล่าง ควบคุมง่ายและสร้างรูปเกือกม้าที่หลังแขนได้ดีมาก', 'จับบาร์เคเบิลไว้ระดับอก ล็อกข้อศอกแนบชิดลำตัวห้ามขยับ | ออกแรงจากหลังแขน กดบาร์ลงด้านล่างจนแขนเหยียดตึง | ผ่อนบาร์ขึ้นกลับมาระดับอกอย่างช้าๆ', NULL, 'https://www.youtube.com/embed/2-LAMcpzODU'),
('ดิปส์หลังแขน', 'Bench Dips', 'ปานกลาง', 'แขน', 'หน้าอก, หัวไหล่', 'น้ำหนักตัว', '5-10 นาที', 'ใช้น้ำหนักตัวดันกับม้านั่งหรือเก้าอี้ ทำได้ง่ายๆ ที่บ้านเพื่อกระชับต้นแขน', 'นั่งบนขอบเก้าอี้ วางมือไว้ข้างสะโพก เหยียดขาไปด้านหน้า | ขยับก้นลอยออกจากเก้าอี้ ย่อตัวลงจนข้อศอกตั้งฉาก 90 องศา | ออกแรงดันจากฝ่ามือและหลังแขน ดันตัวกลับขึ้นมา', NULL, 'https://www.youtube.com/embed/c3ZGl4pAwZ4'),
('เหยียดหลังแขน', 'Tricep Kickback', 'ปานกลาง', 'แขน', 'ไม่มี', 'ดัมเบล', '10-15 นาที', 'โน้มตัวแล้วเตะแขนไปด้านหลัง เน้นการบีบเกร็ง (Squeeze) ของหลังแขนในจุดที่ตึงที่สุด', 'วางมือและเข่าข้างหนึ่งบนเบาะ โน้มตัวให้หลังขนานพื้น | ยกข้อศอกขึ้นมาแนบลำตัวให้ตั้งฉาก | ออกแรงเหยียดปลายแขนไปด้านหลังจนแขนตึง บีบหลังแขน | งอแขนกลับมาที่ตั้งฉาก', NULL, 'https://www.youtube.com/embed/6SS6K3lAwZ8'),
('ดึงหน้าแขนเคเบิล', 'Cable Bicep Curl', 'เริ่มต้น', 'แขน', 'ปลายแขน', 'เครื่องเล่น', '10-15 นาที', 'แรงต้านคงที่จากเครื่องเคเบิลช่วยให้กล้ามเนื้อทำงานตลอดเวลา ไม่มีการพักโกง', 'ยืนตรง หันหน้าเข้าหาเครื่องเคเบิล จับบาร์จากด้านล่าง | ล็อกข้อศอกแนบลำตัว ดึงบาร์ขึ้นมาหาหน้าอก | ปล่อยบาร์ลงช้าๆ ต้านแรงดึงของสายเคเบิล', NULL, 'https://www.youtube.com/embed/AsAQMCj2N6E');
INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('แพลงก์', 'Plank', 'เริ่มต้น', 'หน้าท้อง', 'หัวไหล่, หลังล่าง', 'น้ำหนักตัว', '5-10 นาที', 'สุดยอดท่าฝึกความแข็งแรงของกล้ามเนื้อแกนกลางลำตัว ช่วยลดพุงและเพิ่มความมั่นคง', 'คว่ำหน้า วางท่อนแขนและข้อศอกลงบนพื้นให้ตรงกับหัวไหล่ | เหยียดขาตึงไปด้านหลัง ตั้งปลายเท้าขึ้น | เกร็งหน้าท้องและก้น ล็อกลำตัวให้ตรงเป็นแผ่นกระดาน (ระวังอย่าให้เอวแอ่นหรือโด่งก้น) | ค้างท่าไว้ 30-60 วินาที โดยหายใจปกติ', NULL, 'https://www.youtube.com/embed/pSHjTRCQxIw'),
('ครันช์', 'Crunch', 'เริ่มต้น', 'หน้าท้อง', 'แกนกลางลำตัว', 'น้ำหนักตัว', '5-10 นาที', 'ท่าเกร็งหน้าท้องพื้นฐาน ปลอดภัยต่อกระดูกสันหลังส่วนล่าง เน้นหน้าท้องส่วนบน', 'นอนหงาย ชันเข่าขึ้นทั้งสองข้าง แตะมือเบาๆ ไว้หลังใบหู | เกร็งหน้าท้องเพื่อยกลำตัวส่วนบน (ไหล่และสะบัก) ขึ้นพ้นพื้นเล็กน้อย | ค่อยๆ คลายกล้ามเนื้อและวางแผ่นหลังลงช้าๆ', NULL, 'https://www.youtube.com/embed/Xyd_fa5zoEU'),
('ยกขาคู่', 'Lying Leg Raise', 'ปานกลาง', 'หน้าท้อง', 'แกนกลางลำตัว', 'น้ำหนักตัว', '5-10 นาที', 'เน้นการสร้างกล้ามเนื้อหน้าท้องส่วนล่างโดยเฉพาะ (V-Cut)', 'นอนหงาย สอดฝ่ามือทั้งสองข้างไว้ใต้ก้นเพื่อรองรับหลังล่าง เหยียดขาตึง | เกร็งหน้าท้อง ยกขาทั้งสองข้างขึ้นพร้อมกันจนตั้งฉาก 90 องศากับพื้น | ค่อยๆ ลดขาลงช้าๆ โดยไม่ให้ส้นเท้าแตะพื้น แล้วยกขึ้นใหม่', NULL, 'https://www.youtube.com/embed/JB2fas4fIG0'),
('รัสเซียนทวิสต์ (นั่งบิดลำตัว)', 'Russian Twist', 'ปานกลาง', 'หน้าท้อง', 'แกนกลางลำตัว', 'น้ำหนักตัว', '5-10 นาที', 'ท่าบิดลำตัวยอดฮิต ช่วยกระชับเอวด้านข้างและสร้างร่อง 11', 'นั่งชันเข่า เอนแผ่นหลังลงไปด้านหลังประมาณ 45 องศา (หากต้องการท้าทายให้ยกส้นเท้าลอยพ้นพื้น) | ประสานมือไว้ที่ระดับหน้าอก | บิดลำตัวส่วนบนไปแตะพื้นด้านซ้าย สลับกับบิดไปแตะด้านขวาต่อเนื่อง', NULL, 'https://www.youtube.com/embed/wkD8rjkodUI'),
('ครันช์จักรยาน', 'Bicycle Crunch', 'ปานกลาง', 'หน้าท้อง', 'หน้าท้องด้านข้าง', 'น้ำหนักตัว', '5-10 นาที', 'ท่าที่มีการเคลื่อนไหวต่อเนื่อง เผาผลาญไขมันและโดนกล้ามเนื้อหน้าท้องทุกส่วนในท่าเดียว', 'นอนหงาย ยกขาขึ้นตั้งฉาก แตะมือเบาๆ ไว้ที่หลังใบหู | บิดลำตัวโดยนำข้อศอกซ้ายไปแตะกับเข่าขวาที่ดึงเข้ามา พร้อมกับเหยียดขาซ้ายออกไปตรงๆ ลอยเหนือพื้น | สลับข้างทันที โดยนำศอกขวาไปแตะเข่าซ้าย', NULL, 'https://www.youtube.com/embed/9FGilxCbdz8'),
('แตะส้นเท้า', 'Heel Touches', 'เริ่มต้น', 'หน้าท้อง', 'หน้าท้องด้านข้าง', 'น้ำหนักตัว', '5-10 นาที', 'ท่าง่ายๆ นอนทำได้สบายๆ สำหรับบริหารกล้ามเนื้อเอวด้านข้าง', 'นอนหงาย ชันเข่าทั้งสองข้าง วางแขนตึงไว้ข้างลำตัว | เกร็งหน้าท้องยกสะบักขึ้นจากพื้นเล็กน้อย | เอี้ยวตัวไปด้านข้างเพื่อเอื้อมมือขวาไปแตะส้นเท้าขวา | สลับเอี้ยวตัวเอื้อมมือซ้ายไปแตะส้นเท้าซ้าย', NULL, 'https://www.youtube.com/embed/9bXEn2Xq1X0'),
('เครื่องบริหารหน้าท้อง', 'Ab Crunch Machine', 'เริ่มต้น', 'หน้าท้อง', 'แกนกลางลำตัว', 'เครื่องเล่น', '10-15 นาที', 'เพิ่มแรงต้านให้หน้าท้องด้วยเครื่องเล่น สร้างกล้ามท้องเป็นมัดให้ชัดเจนและหนาขึ้น', 'นั่งพิงหลังบนเครื่อง จับด้ามจับเหนือศีรษะและวางเท้าบนแท่นรอง | หายใจออก เกร็งหน้าท้องเพื่อดึงแผ่นหลังและเข่าพับเข้าหากัน | หายใจเข้า ค่อยๆ ปล่อยตัวต้านน้ำหนักกลับไปสู่ท่าเริ่มต้น', NULL, 'https://www.youtube.com/embed/2u3sB9f7H3A');
INSERT INTO exercises (name_th, name_en, difficulty, muscle_group, secondary_muscle, equipment, duration, description, instructions, media_url, video_url) VALUES 
('ท่าปีนเขา', 'Mountain Climber', 'ปานกลาง', 'ทั่วร่าง', 'หน้าท้อง, หัวไหล่', 'น้ำหนักตัว', '5-10 นาที', 'สุดยอดท่าคาร์ดิโอผสมบอดี้เวท ได้กระชับทั้งหน้าท้อง แขน ขา และเบิร์นไขมันกระจุย', 'ตั้งท่าแพลงก์แขนเหยียดตึง (เหมือนท่าเตรียมวิดพื้น) ลำตัวตรงขนานพื้น | งอเข่าขวา ดึงดึงเข่าเข้าหาหน้าอกอย่างรวดเร็ว | ดึงขาขวากลับไปที่เดิม พร้อมกับสลับดึงเข่าซ้ายเข้าหาหน้าอก | ทำสลับซ้ายขวาต่อเนื่องด้วยความเร็วเหมือนกำลังวิ่งอยู่กับที่', NULL, 'https://www.youtube.com/embed/nmwgirgXLYM');